### **8. ⚠️ MEDIUM: Missing Error Handling & Logging**
**Issue**: No try-catch blocks, no security logging, unhandled rejections.
- **Risk**: Information disclosure through error messages, inability to detect attacks
- **OWASP**: A09:2021 – Security Logging and Monitoring Failures

**Recommendation**:
```javascript
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

app.get('/users', authenticateToken, (req, res) => {
  try {
    logger.info('User data request', { userId: req.user.id, timestamp: new Date() });

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    logger.error('Error fetching users', { error: error.message, userId: req.user.id });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Global error handler
app.use((err, req, res, next) => {
  logger.error('Unhandled error', { error: err.message, stack: err.stack });
  res.status(500).json({ error: 'Internal server error' });
});

process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled Rejection at:', promise, 'reason:', reason);
  process.exit(1);
});
```

