const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const { query, validationResult } = require('express-validator');
const winston = require('winston');
require('dotenv').config();

// Validate environment
const requiredEnvVars = ['JWT_SECRET', 'NODE_ENV'];
requiredEnvVars.forEach(envVar => {
  if (!process.env[envVar]) {
    console.error(`Fatal: Missing environment variable: ${envVar}`);
    process.exit(1);
  }
});

const app = express();

// Security middleware
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://localhost'],
  credentials: true,
  methods: ['GET', 'POST']
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});
const strictLimiter = rateLimit({
  windowMs: 5 * 60 * 1000,
  max: 5
});

app.use(limiter);

// Logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

// Authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader?.split(' ')[1];

  if (!token) {
    logger.warn('Missing authentication token', { ip: req.ip });
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);
    req.user = user;
    next();
  } catch (err) {
    logger.warn('Invalid token', { ip: req.ip, error: err.message });
    return res.status(403).json({ error: 'Invalid token' });
  }
};

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', authenticateToken, strictLimiter,
  query('limit').optional().isInt({ min: 1, max: 100 }),
  query('offset').optional().isInt({ min: 0 }),
  (req, res) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({ errors: errors.array() });
      }

      if (req.user.role !== 'admin') {
        logger.warn('Unauthorized access attempt', { userId: req.user.id });
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      logger.info('User data accessed', { userId: req.user.id });

      res.json([
        { id: 1, name: 'Alice', email: 'alice@example.com' },
        { id: 2, name: 'Bob', email: 'bob@example.com' },
      ]);
    } catch (error) {
      logger.error('Error fetching users', { error: error.message });
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Error handler
app.use((err, req, res, next) => {
  logger.error('Unhandled error', { error: err.message });
  res.status(500).json({ error: 'Internal server error' });
});

// Server startup
if (process.env.NODE_ENV === 'production') {
  const options = {
    key: fs.readFileSync(process.env.SSL_KEY_PATH),
    cert: fs.readFileSync(process.env.SSL_CERT_PATH)
  };
  https.createServer(options, app).listen(443, () => {
    logger.info('HTTPS server started on port 443');
  });
} else {
  app.listen(3000, () => {
    logger.info('HTTP server started on port 3000');
  });
}

module.exports = app;
```

